mapper.select:
SELECT c.CC_SEQ, c.FAMILY_ID, c.CC_NM, c.CC_TYPE, c.SOURCE_PLAN_SEQ, c.INCOME_PLAN_SEQ, p.PLAN_NM AS INCOME_PLAN_NM, c.MONTHLY_AMT, c.SORT_ORDER, c.USE_YN, c.DEL_YN, c.MEMO, c.REG_ID, c.REG_DT, c.UPD_ID, c.UPD_DT, (SELECT COUNT(*) FROM CASH_FLOW_PLAN_MST e WHERE e.COST_CENTER_TYPE = 'CC' AND e.COST_CENTER_SEQ = c.CC_SEQ AND e.DEL_YN = 'N') AS USED_COUNT FROM COST_CENTER_MST c LEFT JOIN CASH_FLOW_PLAN_MST p ON p.PLAN_SEQ = c.INCOME_PLAN_SEQ AND p.DEL_YN = 'N' WHERE c.FAMILY_ID = #{familyId} AND c.DEL_YN = 'N'
AND c.USE_YN = #{useYn}
ORDER BY c.CC_TYPE ASC, c.SORT_ORDER ASC, c.CC_SEQ ASC

mapper.update:
UPDATE COST_CENTER_MST
SET DEL_YN = 'Y',
    UPD_ID = #{updId},
    UPD_DT = NOW()
WHERE FAMILY_ID = #{familyId}
  AND CC_SEQ    = #{ccSeq}

UPDATE COST_CENTER_MST
SET DEL_YN = 'Y',
    UPD_ID = #{updId},
    UPD_DT = NOW()
WHERE FAMILY_ID        = #{familyId}
  AND SOURCE_ASSET_SEQ = #{sourceAssetSeq}

mapper.select:
SELECT COUNT(*)
FROM CASH_FLOW_PLAN_MST
WHERE FAMILY_ID         = #{familyId}
  AND COST_CENTER_TYPE  = 'CC'
  AND COST_CENTER_SEQ   = #{ccSeq}
  AND DEL_YN            = 'N'

SELECT COUNT(*)
FROM COST_CENTER_MST
WHERE FAMILY_ID       = #{familyId}
  AND INCOME_PLAN_SEQ = #{incomePlanSeq}
  AND DEL_YN          = 'N'
